# Fix

查询规格文档，我们发现 Filter 的值只能是 Name 或 Name 数组，那就很好解决了。


  ![](https://v6.gh-proxy.org/https://github.com/CuB3y0nd/picx-images-hosting/raw/master/.2oc1tajc0o.avif)


我们可以直接禁止 Filter 中出现 Indirect Reference，或者检测 Stream 自引用等……出于性能考虑，我选择直接挡 `objRef` 类型：

```cpp ins={22, 33-27}
Stream *Stream::addFilters(Object *dict) {
  Object obj, obj2;
  Object params, params2;
  Stream *str;
  int i;

  str = this;
  dict->dictLookup("Filter", &obj);
  if (obj.isNull()) {
    obj.free();
    dict->dictLookup("F", &obj);
  }
  dict->dictLookup("DecodeParms", &params);
  if (params.isNull()) {
    params.free();
    dict->dictLookup("DP", &params);
  }
  if (obj.isName()) {
    str = makeFilter(obj.getName(), str, &params);
  } else if (obj.isArray()) {
    for (i = 0; i < obj.arrayGetLength(); ++i) {
      obj.arrayGetNF(i, &obj2);
      if (params.isArray())
        params.arrayGet(i, &params2);
      else
        params2.initNull();
      if (obj2.isRef()) {
        error(getPos(), "Indirect reference is not allowed in Filter");
        str = new EOFStream(str);
        obj2.free();
        params2.free();
        break;
      }
      if (obj2.isName()) {
        str = makeFilter(obj2.getName(), str, &params2);
      } else {
        error(getPos(), "Bad filter name");
        str = new EOFStream(str);
      }
      obj2.free();
      params2.free();
    }
  } else if (!obj.isNull()) {
    error(getPos(), "Bad 'Filter' attribute in stream");
  }
  obj.free();
  params.free();

  return str;
}
```

可以看到，我们成功将无限递归扼杀在了摇篮里 xD


