  v2 = helper_mov_imm(a1, v1, 64LL, 0LL);
  v3 = helper_mov_imm(a1, v2, 16LL, 0LL);
  v4 = helper_mov_imm(a1, v3, 8LL, 0LL);
  v5 = helper_mov_imm(a1, v4, 4LL, 0LL);
  v6 = helper_mov_imm(a1, v5, 2LL, 0LL);
